def safe_int(campo: str, valor: str):
    texto = valor.strip()
    if texto == "":
        return (False, None, f"ERROR en {campo!r}: vacío (raw={valor!r})")
    try:
        return (True, int(texto), None)
    except ValueError:
        return (False, None, f"ERROR en {campo!r}: no es entero (raw={valor!r})")

for v in [" 21 ", "", "abc", "  "]:
    print(repr(v), "→", safe_int("edad", v))

from decimal import Decimal, ROUND_HALF_EVEN, InvalidOperation

def parse_pipeline(edad_txt: str, monto_txt: str) -> dict:
    raw = {"edad": edad_txt, "monto": monto_txt}
    clean = {"edad": None, "monto": None}
    errors = []
    t = edad_txt.strip()
    if not t:
        errors.append(f"ERROR en 'edad': vacío (raw={edad_txt!r})")
    else:
        try:
            clean["edad"] = int(t)
        except ValueError:
            errors.append(f"ERROR en 'edad': no int (raw={edad_txt!r})")
    m = monto_txt.strip()
    if not m:
        errors.append(f"ERROR en 'monto': vacío (raw={monto_txt!r})")
    else:
        try:
            clean["monto"] = Decimal(m).quantize(Decimal("0.01"), rounding=ROUND_HALF_EVEN)
        except InvalidOperation:
            errors.append(f"ERROR en 'monto': no Decimal (raw={monto_txt!r})")
    return {"raw": raw, "clean": clean, "errors": errors}

print(parse_pipeline(" 21 ", "150.50"))
print(parse_pipeline("abc", "10.00"))
print(parse_pipeline("30", "xx"))

